#include <iostream>
#include <string>

// Class: data + behavior
class Player {
public:
    // Fields (data)
    std::string name;
    int health;
    int attack;
    int defense;
    int level;
    double experience;

    // Constructor: called when an object is created
    Player(std::string n, int h, int a, int d) {
        name = n;
        health = h;
        attack = a;
        defense = d;
        level = 1;
        experience = 0.0;
        std::cout << "Player " << name << " created!" << std::endl;
    }

    // Methods (behavior)
    void displayStats() {
        std::cout << "\n=== Player Stats ===" << std::endl;
        std::cout << "Name: " << name << std::endl;
        std::cout << "Level: " << level << std::endl;
        std::cout << "Health: " << health << std::endl;
        std::cout << "Attack: " << attack << std::endl;
        std::cout << "Defense: " << defense << std::endl;
        std::cout << "Experience: " << experience << std::endl;
    }

    void takeDamage(int damage) {
        int actualDamage = damage - (defense / 2);
        if (actualDamage < 0) actualDamage = 0;
        health -= actualDamage;
        std::cout << name << " took " << actualDamage << " damage!" << std::endl;
        if (health <= 0) {
            health = 0;
            std::cout << name << " has been defeated!" << std::endl;
        }
    }

    void gainExperience(double exp) {
        experience += exp;
        std::cout << name << " gained " << exp << " experience!" << std::endl;

        // Level up if enough experience
        int requiredExp = level * 100;
        if (experience >= requiredExp) {
            level++;
            health += 20;
            attack += 5;
            defense += 3;
            std::cout << name << " leveled up to level " << level << "!" << std::endl;
            experience = 0;
        }
    }

    void attackEnemy(int enemyHealth) {
        std::cout << name << " attacks for " << attack << " damage!" << std::endl;
        enemyHealth -= attack;
        if (enemyHealth <= 0) {
            std::cout << "Enemy defeated!" << std::endl;
            gainExperience(50);
        }
    }
};

int main() {
    std::cout << "=== Classes & Objects ===" << std::endl;

    // Create a Player object
    Player hero("Aragorn", 100, 20, 12);

    // Display initial stats
    hero.displayStats();

    // Use methods
    hero.attackEnemy(50);

    hero.takeDamage(30);
    hero.displayStats();

    return 0;
}

phase1.explanation:
🎮 **Classes are blueprints. Objects are instances.**

**Class structure:**
```cpp
class Player {
public:  // Access specifier
    // Fields (data)
    std::string name;
    int health;

    // Constructor (special method)
    Player(std::string n) {
        name = n;
        health = 100;
    }

    // Methods (behavior)
    void takeDamage(int damage) {
        health -= damage;
    }
};
```

**Key concepts:**
| Concept | What it is |
|---------|------------|
| Class | Blueprint for objects |
| Object | An instance of a class |
| Constructor | Called when object is created |
| Method | Function that belongs to a class |
| Field | Data that belongs to a class |

**Creating objects:**
```cpp
Player hero("Aragorn", 100, 20, 12);
Player enemy("Goblin", 30, 8, 2);
```

**Why classes matter for games:**
- Each player is a `Player` object
- Each enemy is an `Enemy` object
- Each item is an `Item` object
- Methods define what objects can do

