#include <iostream>
#include <string>

class Enemy {
public:
    std::string name;
    int health;
    int damage;
    bool isAlive;

    Enemy(std::string n, int h, int d) {
        name = n;
        health = h;
        damage = d;
        isAlive = true;
        std::cout << name << " spawned!" << std::endl;
    }

    void takeDamage(int d) {
        health -= d;
        std::cout << name << " took " << d << " damage!" << std::endl;
        if (health <= 0) {
            health = 0;
            isAlive = false;
            std::cout << name << " defeated!" << std::endl;
        }
    }

    void displayStats() {
        std::cout << "\n=== Enemy Stats ===" << std::endl;
        std::cout << "Name: " << name << std::endl;
        std::cout << "Health: " << health << std::endl;
        std::cout << "Damage: " << damage << std::endl;
        std::cout << "Alive: " << (isAlive ? "Yes" : "No") << std::endl;
    }

    int getDamage() {
        return damage;
    }
};

int main() {
    Enemy goblin("Goblin", 30, 8);

    goblin.displayStats();

    goblin.takeDamage(15);
    goblin.displayStats();

    goblin.takeDamage(20);
    goblin.displayStats();

    return 0;
}
